#include<bits/stdc++.h>
#define N 1510
using namespace std;
char a[N][N];
long long ans;
int b[N][N],l[N],r[N],n;
int main()
{
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%s%d",a[i]+1,&r[i]);
	}
	for(int i=1;i<=n;i++)
	{
		scanf("%d",&l[i]);
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			if(a[i][j]=='R')
			{
				b[i][j+1]+=b[i][j]+1;
			}
			else
			{
				b[i+1][j]+=b[i][j]+1;
			}
			b[i][j]++;
		}
	}
	for(int i=1;i<=n;i++)
	{
		ans+=b[n+1][i]*l[i]+b[i][n+1]*r[i];
	}
	printf("%d\n",ans);
	int q;
	scanf("%d",&q);
	while(q--)
	{
		int x,y;
		scanf("%d%d",&x,&y);
		int temp=b[x][y],tempx=x,tempy=y;
		while(x!=n+1&&y!=n+1)
		{
			if(a[x][y]=='R')
			{
				y++;
			}
			else
			{
				x++;
			}
			b[x][y]-=temp;
		}
		if(x==n+1)
		{
			ans-=temp*l[y];
		}
		else
		{
			ans-=temp*r[x];
		}
		x=tempx,y=tempy;
		if(a[x][y]=='D')
		{
			a[x][y]='R';
		}
		else
		{
			a[x][y]='D';
		}
		temp=b[x][y];
		while(x!=n+1&&y!=n+1)
		{
			if(a[x][y]=='R')
			{
				y++;
			}
			else
			{
				x++;
			}
			b[x][y]+=temp;
		}
		if(x==n+1)
		{
			ans+=temp*l[y];
		}
		else
		{
			ans+=temp*r[x];
		}
		printf("%d\n",ans);
	}
	return 0;
}
